var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자기, 어째 걱정거리가 있어 보이는 얼굴이네?","JPN":"ダーリン、なんだか心配事がありそうな顔ね。","ENG":"Sweetie, you look like you're worried about something.","TWN":"親愛的，你怎麼一臉心事重重的樣子？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"여긴 참 이상한 술집이군.","JPN":"このバーは変だな。","ENG":"What a strange bar this is.","TWN":"這間酒吧真奇怪。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"사탕 달라고 졸라대는 꼬맹이에, 불온한 말투로 작업을 걸어오는 만취한 여자라니.","JPN":"キャンディをねだるチビに、不穏な口調でナンパをしてくる酔っ払いの女とは。","ENG":"There's a kid pestering for candy, and a drunk woman approaching me with a seditious tone for some reason.","TWN":"有跟我要糖的小鬼，還有爛醉的女人用危險的語氣跟我搭訕。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"얌전히 술만 마시는 것도 좋지만 그런 사나운 표정 짓고 있으면 손님들이 도망가요.","JPN":"大人しくお酒だけ飲んでるのもいいけど、そんな険しい顔をしてるとお客さんが逃げちゃうわ。","ENG":"It's nice to just sit and have a drink, but if you keep making that scary face, all the customers will run away.","TWN":"安靜喝酒是很好啦，但你臉那麼臭，客人都要被你嚇跑了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 그 원숭이. 여길 소개해준 건 결국 날 물 먹이려는 수작이었나?","JPN":"ふん、あのサル。ここを紹介してくれたのは、結局私を困らせるためだったのか？","ENG":"Hmph, that monkey. She introduced this place to me to give me the middle finger, didn't she?","TWN":"哼，那隻死猴子。介紹我來這裡，結果只想看我出糗嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐야아? 지인소개로 온 거구나? 그럼 한잔 공짜로 만들어 줄게.","JPN":"何？　知り合いの紹介で来たのね。じゃあ、ただで1杯あげるわ。","ENG":"Oh? Did you come here by recommendation? Then I'll make you a drink on the house.","TWN":"唉呀？原來是朋友介紹的啊？那我請你喝一杯吧。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신… 주정뱅이가 아니라 이 가게 직원이었어?","JPN":"お前……酔っ払いではなくてこの店の職員だったのか？","ENG":"You're... not a drunk but an employee of this bar?","TWN":"你……不是醉鬼，而是這家店的員工？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"주정뱅이긴 하지만 일단은 점장이야. 그레모리 씨라고 부르면 돼.","JPN":"酔っ払いではあるけど、一応は店長よ。グレモリーさんでいいわ。","ENG":"I am a drunk, but I'm also the manager. Call me Gremory.","TWN":"雖然我也算醉鬼沒錯，但我是店長。叫我葛茉莉就好。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"본명은 아닌 걸 보니 숨기는 게 많은 모양이지?","JPN":"本名ではないな。隠し事が多いようだが。","ENG":"Seeing how it's not your real name, you must have a lot to hide, eh?","TWN":"名字也不是本名，看來你祕密不少嘛？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머- 용한 분께서 손님으로 오셨네.","JPN":"あら。とても頭の切れるお客さんだったのね。","ENG":"Oh, my. Looks like we got ourselves a mind reader here.","TWN":"哎呀～厲害的客人上門了呢。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…한잔하러 왔을 뿐이야. 딱히 당신에게 용무는 없어.","JPN":"……飲みに来ただけだ。別にお前に用はない。","ENG":"...I'm just here for a drink. I have no business for you.","TWN":"……我只是來喝一杯，沒打算找你麻煩。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그라운드원에 우리 가게만큼 값싸게 취하기 좋은 곳이 없긴 하지.","JPN":"グラウンド・ワンにうちの店ほど安くて飲みやすいところはないわね。","ENG":"There's not a bar in Ground One where you can get drunk as cheaply as ours.","TWN":"在G1買醉，沒有比我們店更便宜的地方了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"근데 그거 알아? 여기 무료로 사랑 점도 봐준다?","JPN":"でも、それ知ってる？　ここは無料で恋愛占いもしてくれるのよ。","ENG":"But did you know? We offer fortunetelling for free here.","TWN":"不過你知道嗎？我們這裡還免費幫人戀愛占卜喔？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"관심 없어.","JPN":"興味ない。","ENG":"Not interested.","TWN":"我沒興趣。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"정말? 고민이 있다면 얼마든지 들어줄 수도 있는데.","JPN":"本当に？　悩み事があったらいくらでも聞いてあげられるわ。","ENG":"Really? I'm all ears if you have any concerns you wish to talk about.","TWN":"真的嗎？如果你有煩惱，我也可以聽你說哦。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"처음보는 사람에게 내 사적인 이야길 털어놓는 취미는 없거든.","JPN":"初対面の人に自分のプライバシーを話す趣味はないからな。","ENG":"I'm not one to talk about my personal life to a stranger I just met.","TWN":"我可沒興趣跟第一次見面的人聊私事。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자, 점장표 특제 칵테일 데몬 레이디야.","JPN":"はい。店長特製のカクテル、デーモンレディーよ。","ENG":"Here you go. The manager's special cocktail, Demon Lady.","TWN":"來，這杯是店長特製雞尾酒惡魔淑女。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"너무 독해서 쓰러질 지도 모르니 조심해.","JPN":"強くて倒れることになるかもしれないから気をつけなさい。","ENG":"It's strong, so be careful not to faint.","TWN":"這很烈，小心不要喝掛了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 날 뭘로 보고….","JPN":"ふん、私を何だと思って……","ENG":"Hmph. Who do you think I am?","TWN":"哼，你把我當成什麼……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"평소 관심있던 남자사람친구나 신경쓰이는 부하직원 한 명쯤 있지 않아?","JPN":"普段気にしている男の友だちとか、気になる部下とかが1人いたりしない？","ENG":"Don't you have a male friend or a subordinate that you care about?","TWN":"你平時難道沒有在意的男性朋友，或讓你掛心的部下嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"푸흡…! 콜록 콜록!","JPN":"ぷっ……！　ゲホ、ゲホ……！","ENG":"Pfft...! *Cough!* *Cough!*","TWN":"噗……！咳、咳咳！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 독하니까 조심하래도.","JPN":"あら、強いから気をつけなさいって言ったじゃない。","ENG":"See? I told you it's strong.","TWN":"哎呀，我不是說這很烈，要你小心點喝嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 느닷없이 이상한 소릴해서 그런 거야!","JPN":"お前がいきなり変なことを言うからだろう！","ENG":"This is because you started talking about nonsense!","TWN":"還不都是因為你突然說些奇怪的話害的！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"미안. 이제 찍소리 안하고 얌전히 있을게.","JPN":"ごめん。もう黙って大人しくしてるわね。","ENG":"Sorry, I won't say a word from now on.","TWN":"抱歉啦，我會乖乖閉嘴的。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그렇게 빤히 쳐다보기만 할 거면, 차라리 하고 싶은 말을 하지 그래?","JPN":"そうやってじっと見ているようなら、いっそ言いたいことを言ったらどうだ？","ENG":"If you're going to keep staring at me like that, why don't you just say what you want to say?","TWN":"你要是只打算這樣盯著我看，倒不如直接說出你想說的話？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"역시 있는 거지? 신경 쓰이는 사람!","JPN":"やっぱりいるのね？　気になる人！","ENG":"So you do have someone you're interested in, right?!","TWN":"果然有吧？讓你在意的人！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…있다면 어쩔 건데?","JPN":"……いたらどうする？","ENG":"...So what if I do?","TWN":"……就算有又怎樣？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"고민이 있으면 같이 터놓고 얘기나 해보자는 거야.","JPN":"悩みがある時には、人に打ち明けてみるのも良い手よ。","ENG":"I'm just saying that we could talk about our worries to each other.","TWN":"如果有煩惱，我們就敞開心扉聊聊嘛。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"같은 여자끼리 내숭떨 필요도 없잖아?","JPN":"同じ女同志、猫を被る必要もないじゃない？","ENG":"There's no need to be coy in girls' talk, right?","TWN":"同樣都是女人，沒什麼好害羞的吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래? 당신 눈에는 내가 수다나 떠는 평범한 여자로 보이는 모양이지?","JPN":"そうか？　お前の目には私がおしゃべり好きの普通の女に見えるようだな。","ENG":"Oh really? So in your eyes, I look like an ordinary girl who likes to chat, hmm?","TWN":"是嗎？我看起來像是愛聊天的普通女人嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"평범하지 않으면 대화도 할 수 없는 거야?","JPN":"普通じゃないと会話もできないの？","ENG":"So ordinary people are the only ones allowed to have a chat?","TWN":"不是普通女人，就不能聊天了？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};